+        assert!(config.sampled_metrics.is_empty());
+
+        let dbg = format!("{config:?}");
+        assert!(dbg.contains("SamplingConfig"));
+
+        let cloned = config.clone();
+        assert!((cloned.sample_rate - 1.0).abs() < f64::EPSILON);
